class Solution:
    def checkDivisibility(self, n):
        s = str(n)
        digit_sum = 0
        digit_prod = 1
        for ch in s:
            d = int(ch)
            digit_sum += d
            digit_prod *= d
        return n % (digit_sum + digit_prod) == 0

