var checkDivisibility = function(n) {
    let m = n, digitSum = 0, digitProd = 1;
    while (m > 0) {
        const d = m % 10;
        digitSum += d;
        digitProd *= d;
        m = Math.floor(m / 10);
    }
    return n % (digitSum + digitProd) === 0;
};
